// 🌟 修复：清洗 SVG 中写死的黑色，让它能跟随 CSS 变色
const getDepartmentIcon = (departmentName) => {
  // 默认使用公文通的图标（第一个）
  const defaultIcon = SOURCE_ICON_CATALOG[0];
  if (!departmentName)
    return defaultIcon.svg
      .replace(/fill="black"/g, 'fill="currentColor"')
      .replace(/fill-opacity="0\.85"/g, "");

  const found = SOURCE_ICON_CATALOG.find(
    (item) => item.name === departmentName,
  );
  // 如果找不到匹配的部门，使用公文通的图标
  const svgToUse = found ? found.svg : defaultIcon.svg;
  return svgToUse
    .replace(/fill="black"/g, 'fill="currentColor"')
    .replace(/fill-opacity="0\.85"/g, "");
};

// 🌟 新增：获取部门对应的筛选栏专属颜色
const getDepartmentColor = (departmentName) => {
  const index = SOURCE_ICON_CATALOG.findIndex(
    (item) => item.name === departmentName,
  );
  // 如果找到了对应的部门，并且有对应的 FILTER_CHIP_COLORS
  if (index !== -1 && FILTER_CHIP_COLORS[index]) {
    return FILTER_CHIP_COLORS[index];
  }
  // 默认使用公文通的颜色（第一个）
  return FILTER_CHIP_COLORS[0] || "rgb(2, 132, 199)";
};

// 🌟 新增：获取 AI 标签背景色（带透明度）
const getAITagBgColor = (departmentName) => {
  const color = getDepartmentColor(departmentName);
  // 将 rgb(r,g,b) 转换为 rgba(r,g,b,0.7)
  const match = color.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
  if (match) {
    return `rgba(${match[1]}, ${match[2]}, ${match[3]}, 0.8)`;
  }
  return color;
};

// 🌟 新增：获取订阅管理中的来源颜色（带 0.8 透明度）
const getSubsChipColor = (sourceName) => {
  const index = SOURCE_ICON_CATALOG.findIndex(
    (item) => item.name === sourceName,
  );
  let color;
  if (index !== -1 && FILTER_CHIP_COLORS[index]) {
    color = FILTER_CHIP_COLORS[index];
  } else {
    color = FILTER_CHIP_COLORS[0] || "rgb(2, 132, 199)";
  }
  // 将 rgb(r,g,b) 转换为 rgba(r,g,b,0.8)
  const match = color.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
  if (match) {
    return `rgba(${match[1]}, ${match[2]}, ${match[3]}, 0.8)`;
  }
  return color;
};

// 🌟 新增：获取订阅管理中的来源图标
const getSubsIcon = (sourceName) => {
  const found = SOURCE_ICON_CATALOG.find((item) => item.name === sourceName);
  const svgToUse = found ? found.svg : SOURCE_ICON_CATALOG[0].svg;
  return svgToUse
    .replace(/fill="black"/g, 'fill="currentColor"')
    .replace(/fill-opacity="0\.85"/g, "");
};

// 🌟 新增：获取订阅管理中的卡片样式（支持渐变色）
const getSubsChipStyle = (sourceName, isActive) => {
  if (!isActive) return {};

  // 检查是否有特殊渐变色
  if (SPECIAL_GRADIENT_COLORS[sourceName]) {
    return {
      background: SPECIAL_GRADIENT_COLORS[sourceName],
      color: "#ffffff",
    };
  }

  // 默认使用普通颜色
  const color = getSubsChipColor(sourceName);
  return {
    backgroundColor: color,
    color: "#ffffff",
  };
};

// 🌟 新增：获取订阅管理中的图标样式
const getSubsIconStyle = (sourceName, isActive) => {
  if (isActive) {
    return {
      backgroundColor: "rgba(255,255,255,0.25)",
      color: "#ffffff",
    };
  }

  // 未选中时，检查是否是特殊渐变色
  if (SPECIAL_GRADIENT_COLORS[sourceName]) {
    return {
      background: SPECIAL_GRADIENT_COLORS[sourceName],
      color: "#ffffff",
    };
  }

  // 默认使用普通颜色
  const color = getSubsChipColor(sourceName);
  return {
    backgroundColor: color,
    color: sourceName === "创意设计学院" ? "#ffffff" : undefined,
  };
};

// ============================================================
// 🛡️ 全局安全 API 调用包装器
// ============================================================
// 解决 pywebview.http_server 模式下 API 方法可能未就绪的问题

// 🌟 全局标记：pywebview 是否已确认就绪
let _pywebviewReady = false;

const apiMethodReadyPromises = new Map();
let configHydrated = false;

// 🌟 等待单个 pywebview API 方法就绪，避免把所有调用都绑在同一个方法上
// 启动阶段在 pywebview/http-server 模式下可能需要二十多秒才能真正把 API 方法注入完成
// 这里把等待窗口放宽，避免前端过早判定失败，把启动配置和首屏数据都打成“默认值”。
const waitForApiMethod = (methodName, timeout = 10000) => {
  if (apiMethodReadyPromises.has(methodName)) {
    return apiMethodReadyPromises.get(methodName);
  }

  const readyPromise = new Promise((resolve) => {
    const startTime = Date.now();
    let settled = false;

    const finish = (ready) => {
      if (settled) return;
      settled = true;
      resolve(ready);
      apiMethodReadyPromises.delete(methodName);
    };

    const check = () => {
      const api = window.pywebview?.api;
      if (api && typeof api[methodName] === "function") {
        _pywebviewReady = true;
        finish(true);
        return;
      }

      if (Date.now() - startTime >= timeout) {
        finish(false);
        return;
      }

      setTimeout(check, 100);
    };

    if (window.pywebview?.api) {
      check();
    } else {
      window.addEventListener(
        "pywebviewready",
        () => {
          _pywebviewReady = true;
          check();
        },
        { once: true },
      );
      setTimeout(check, 100);
    }
  });

  apiMethodReadyPromises.set(methodName, readyPromise);
  return readyPromise;
};

// 🌟 安全的 API 调用包装器（带自动等待）
const safeApiCall = async (methodName, ...args) => {
  try {
    if (
      !window.pywebview?.api ||
      typeof window.pywebview.api[methodName] !== "function"
    ) {
      const ready = await waitForApiMethod(methodName);
      if (!ready) {
        return { status: "error", message: `API 方法 ${methodName} 未就绪` };
      }
    }
    const api = window.pywebview?.api;
    if (!api || typeof api[methodName] !== "function") {
      return { status: "error", message: `API 方法 ${methodName} 未就绪` };
    }

    return await api[methodName](...args);
  } catch (e) {
    console.error(`API 调用 ${methodName} 异常:`, e);
    return { status: "error", message: String(e) };
  }
};

// 兼容直接使用 `pywebview.api.xxx` 的旧代码。
// 这里做成动态代理，确保在 `window.pywebview` 迟到注入时也能正常取到最新 API。
const pywebview = new Proxy(
  {},
  {
    get(_target, prop) {
      if (prop === "api") {
        return new Proxy(
          {},
          {
            get(_apiTarget, methodName) {
              const api = window.pywebview?.api;
              const method = api?.[methodName];
              if (typeof method !== "function") return undefined;
              return method.bind(api);
            },
          },
        );
      }

      const value = window.pywebview?.[prop];
      return typeof value === "function" ? value.bind(window.pywebview) : value;
    },
  },
);

